(function ($) {
    $.fn.DataTable = function (options) {
        var settings = $.extend({
            paging: true,
            pageLength: 5,
            searching: true,
            ordering: true,
            info: true,
            columnDefs: []
        }, options || {});

        return this.each(function () {
            var $table = $(this);
            var $tbody = $table.find("tbody");
            var $allRows = $tbody.find("tr");
            var currentPage = 1;
            var sortIndex = -1;
            var sortAsc = true;
            var searchText = "";

            var disabledSortTargets = (settings.columnDefs || [])
                .filter(function (rule) { return rule.orderable === false; })
                .map(function (rule) { return rule.targets; });

            if (settings.searching) {
                var searchId = $table.attr("id") + "_search";
                var $search = $('<input type="search" class="form-control form-control-sm mb-2" placeholder="Search..." id="' + searchId + '" />');
                $table.before($search);
                $search.on("input", function () {
                    searchText = ($(this).val() || "").toString().toLowerCase();
                    currentPage = 1;
                    render();
                });
            }

            var $pager = $('<div class="d-flex gap-2 align-items-center flex-wrap mt-2"></div>');
            if (settings.paging || settings.info) {
                $table.after($pager);
            }

            if (settings.ordering) {
                $table.find("thead th").each(function (index) {
                    var disabled = disabledSortTargets.includes(index) || disabledSortTargets.includes(-1) && index === $table.find("thead th").length - 1;
                    if (disabled) {
                        return;
                    }

                    $(this).css("cursor", "pointer").on("click", function () {
                        if (sortIndex === index) {
                            sortAsc = !sortAsc;
                        } else {
                            sortIndex = index;
                            sortAsc = true;
                        }

                        render();
                    });
                });
            }

            function getFilteredRows() {
                var rows = $allRows.toArray();

                if (searchText) {
                    rows = rows.filter(function (row) {
                        return $(row).text().toLowerCase().indexOf(searchText) >= 0;
                    });
                }

                if (sortIndex >= 0) {
                    rows.sort(function (a, b) {
                        var av = $(a).children().eq(sortIndex).text().trim().toLowerCase();
                        var bv = $(b).children().eq(sortIndex).text().trim().toLowerCase();
                        var an = parseFloat(av);
                        var bn = parseFloat(bv);

                        if (!isNaN(an) && !isNaN(bn)) {
                            return sortAsc ? an - bn : bn - an;
                        }

                        return sortAsc ? av.localeCompare(bv) : bv.localeCompare(av);
                    });
                }

                return rows;
            }

            function render() {
                var rows = getFilteredRows();
                var pageLength = parseInt(settings.pageLength, 10) || 5;
                var totalPages = Math.max(1, Math.ceil(rows.length / pageLength));

                if (currentPage > totalPages) {
                    currentPage = totalPages;
                }

                $tbody.empty();

                var start = settings.paging ? (currentPage - 1) * pageLength : 0;
                var end = settings.paging ? start + pageLength : rows.length;
                rows.slice(start, end).forEach(function (row) {
                    $tbody.append(row);
                });

                if (settings.paging || settings.info) {
                    $pager.empty();
                    if (settings.paging && totalPages > 1) {
                        $pager.append('<button type="button" class="btn btn-sm btn-outline-secondary dt-prev">Previous</button>');
                        $pager.append('<span class="small">Page ' + currentPage + ' of ' + totalPages + '</span>');
                        $pager.append('<button type="button" class="btn btn-sm btn-outline-secondary dt-next">Next</button>');
                    }

                    if (settings.info) {
                        $pager.append('<span class="small text-muted">Showing ' + rows.slice(start, end).length + ' of ' + rows.length + ' records</span>');
                    }

                    $pager.find(".dt-prev").prop("disabled", currentPage <= 1).on("click", function () {
                        if (currentPage > 1) {
                            currentPage--;
                            render();
                        }
                    });

                    $pager.find(".dt-next").prop("disabled", currentPage >= totalPages).on("click", function () {
                        if (currentPage < totalPages) {
                            currentPage++;
                            render();
                        }
                    });
                }
            }

            render();
        });
    };
})(jQuery);
